using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class ClinicService(ApplicationDbContext db)
{
    // === Owners ===

    public async Task<List<Owner>> GetAllOwners()
        => await db.Owners.OrderBy(o => o.LastName).ToListAsync();

    public async Task<Owner?> GetOwner(int id)
        => await db.Owners.Include(o => o.Patients).FirstOrDefaultAsync(o => o.Id == id);

    public async Task<Owner> CreateOwner(Owner owner)
    {
        db.Owners.Add(owner);
        await db.SaveChangesAsync();
        return owner;
    }

    public async Task UpdateOwner(Owner owner)
    {
        db.Owners.Update(owner);
        await db.SaveChangesAsync();
    }

    // === Patients ===

    public async Task<List<Patient>> GetAllPatients(string? search = null)
    {
        var query = db.Patients.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.ToLower();
            query = query.Where(p =>
                p.Name.ToLower().Contains(term) ||
                p.Owner.FirstName.ToLower().Contains(term) ||
                p.Owner.LastName.ToLower().Contains(term));
        }
        return await query.OrderBy(p => p.Name).ToListAsync();
    }

    public async Task<Patient?> GetPatient(int id)
        => await db.Patients
            .Include(p => p.Owner)
            .Include(p => p.TreatmentNotes.OrderByDescending(t => t.CreatedAt))
            .Include(p => p.Appointments.Where(a => a.Status == AppointmentStatus.Scheduled).OrderBy(a => a.StartTime))
            .FirstOrDefaultAsync(p => p.Id == id);

    public async Task<Patient> CreatePatient(Patient patient)
    {
        db.Patients.Add(patient);
        await db.SaveChangesAsync();
        return patient;
    }

    public async Task UpdatePatient(Patient patient)
    {
        db.Patients.Update(patient);
        await db.SaveChangesAsync();
    }

    // === Treatment Notes ===

    public async Task AddTreatmentNote(TreatmentNote note)
    {
        db.TreatmentNotes.Add(note);
        await db.SaveChangesAsync();
    }

    // === Appointments ===

    public async Task<List<Appointment>> GetAppointmentsForDate(DateTime date)
        => await db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

    public async Task<List<Appointment>> GetAppointmentsForWeek(DateTime weekStart)
    {
        var weekEnd = weekStart.AddDays(7);
        return await db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    public async Task<List<DateTime>> GetAvailableSlots(DateTime date)
    {
        var booked = await db.Appointments
            .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .Select(a => a.StartTime)
            .ToListAsync();

        var slots = new List<DateTime>();
        var start = date.Date.AddHours(8);
        var end = date.Date.AddHours(18);
        for (var time = start; time < end; time = time.AddMinutes(30))
        {
            if (!booked.Contains(time))
                slots.Add(time);
        }
        return slots;
    }

    public async Task<Appointment> CreateAppointment(Appointment appointment)
    {
        db.Appointments.Add(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task RescheduleAppointment(int id, DateTime newTime)
    {
        var appt = await db.Appointments.FindAsync(id);
        if (appt != null)
        {
            appt.StartTime = newTime;
            await db.SaveChangesAsync();
        }
    }

    public async Task CancelAppointment(int id)
    {
        var appt = await db.Appointments.FindAsync(id);
        if (appt != null)
        {
            appt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    // === Invoices ===

    public async Task<List<Invoice>> GetAllInvoices(InvoiceStatus? status = null)
    {
        var query = db.Invoices
            .Include(i => i.Patient)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .AsQueryable();
        if (status.HasValue)
            query = query.Where(i => i.Status == status.Value);
        return await query.OrderByDescending(i => i.CreatedAt).ToListAsync();
    }

    public async Task<Invoice?> GetInvoice(int id)
        => await db.Invoices
            .Include(i => i.Patient)
            .Include(i => i.Items)
            .Include(i => i.Payments.OrderByDescending(p => p.PaidAt))
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task<Invoice> CreateInvoice(Invoice invoice)
    {
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task AddInvoiceItem(InvoiceItem item)
    {
        db.InvoiceItems.Add(item);
        await db.SaveChangesAsync();
    }

    public async Task RemoveInvoiceItem(int itemId)
    {
        var item = await db.InvoiceItems.FindAsync(itemId);
        if (item != null)
        {
            db.InvoiceItems.Remove(item);
            await db.SaveChangesAsync();
        }
    }

    // === Payments ===

    public async Task RecordPayment(Payment payment)
    {
        db.Payments.Add(payment);
        var invoice = await db.Invoices.Include(i => i.Items).Include(i => i.Payments).FirstOrDefaultAsync(i => i.Id == payment.InvoiceId);
        if (invoice != null)
        {
            var totalPaid = invoice.Payments.Sum(p => p.Amount) + payment.Amount;
            if (totalPaid >= invoice.Items.Sum(i => i.Amount))
                invoice.Status = InvoiceStatus.Paid;
        }
        await db.SaveChangesAsync();
    }

    public async Task<List<Payment>> GetPaymentHistory(int invoiceId)
        => await db.Payments
            .Where(p => p.InvoiceId == invoiceId)
            .OrderByDescending(p => p.PaidAt)
            .ToListAsync();

    // === Dashboard Stats ===

    public async Task<int> GetTotalPatients()
        => await db.Patients.CountAsync();

    public async Task<int> GetTodayAppointments()
        => await db.Appointments.CountAsync(a => a.StartTime.Date == DateTime.Today && a.Status == AppointmentStatus.Scheduled);

    public async Task<int> GetPendingInvoices()
        => await db.Invoices.CountAsync(i => i.Status == InvoiceStatus.Pending);
}

