@page "/patients"
@attribute [Authorize]

@inject ClinicService ClinicService
@inject NavigationManager Nav

<PageTitle>Patients - VetClinic</PageTitle>

<h1 class="mb-4">Patients</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by pet or owner name..."
               @bind="searchTerm" @bind:event="oninput" @onkeyup="Search" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="() => showForm = !showForm">
            @(showForm ? "Cancel" : "Register New Pet")
        </button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5>Register New Patient</h5>
            <EditForm Model="newPatient" OnValidSubmit="CreatePatient" FormName="newPatientForm">
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Pet Name</label>
                        <InputText class="form-control" @bind-Value="newPatient.Name" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Species</label>
                        <InputText class="form-control" @bind-Value="newPatient.Species" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="newPatient.Breed" />
                    </div>
                </div>
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="newPatient.DateOfBirth" />
                    </div>
                </div>
                <h6 class="mt-3">Owner Information</h6>
                <div class="row mb-2">
                    <div class="col-md-3">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="newOwner.FirstName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="newOwner.LastName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="newOwner.Phone" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="newOwner.Email" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Save</button>
            </EditForm>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr>
            <th>Name</th>
            <th>Species</th>
            <th>Breed</th>
            <th>Owner</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var patient in patients)
        {
            <tr>
                <td>@patient.Name</td>
                <td>@patient.Species</td>
                <td>@patient.Breed</td>
                <td>@patient.Owner.FirstName @patient.Owner.LastName</td>
                <td>
                    <a href="/patients/@patient.Id" class="btn btn-sm btn-outline-primary">View</a>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (!patients.Any())
{
    <p class="text-muted">No patients found.</p>
}

@code {
    private List<Patient> patients = [];
    private string? searchTerm;
    private bool showForm;
    private Patient newPatient = new();
    private Owner newOwner = new();

    protected override async Task OnInitializedAsync()
    {
        patients = await ClinicService.GetAllPatients();
    }

    private async Task Search()
    {
        patients = await ClinicService.GetAllPatients(searchTerm);
    }

    private async Task CreatePatient()
    {
        var owner = await ClinicService.CreateOwner(newOwner);
        newPatient.OwnerId = owner.Id;
        await ClinicService.CreatePatient(newPatient);
        newPatient = new();
        newOwner = new();
        showForm = false;
        patients = await ClinicService.GetAllPatients(searchTerm);
    }
}

@page "/patients/{Id:int}"
@attribute [Authorize]

@inject ClinicService ClinicService
@inject AuthenticationStateProvider AuthStateProvider

<PageTitle>Patient Details - VetClinic</PageTitle>

@if (patient == null)
{
    <p>Loading...</p>
}
else
{
    <h1 class="mb-4">@patient.Name</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="card">
                <div class="card-header d-flex justify-content-between">
                    <span>Pet Information</span>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => editingPet = !editingPet">
                        @(editingPet ? "Cancel" : "Edit")
                    </button>
                </div>
                <div class="card-body">
                    @if (editingPet)
                    {
                        <EditForm Model="patient" OnValidSubmit="SavePatient" FormName="editPatientForm">
                            <div class="mb-2">
                                <label class="form-label">Name</label>
                                <InputText class="form-control" @bind-Value="patient.Name" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Species</label>
                                <InputText class="form-control" @bind-Value="patient.Species" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Breed</label>
                                <InputText class="form-control" @bind-Value="patient.Breed" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Date of Birth</label>
                                <InputDate class="form-control" @bind-Value="patient.DateOfBirth" />
                            </div>
                            <button type="submit" class="btn btn-success btn-sm">Save</button>
                        </EditForm>
                    }
                    else
                    {
                        <p><strong>Species:</strong> @patient.Species</p>
                        <p><strong>Breed:</strong> @patient.Breed</p>
                        <p><strong>Date of Birth:</strong> @(patient.DateOfBirth?.ToString("yyyy-MM-dd") ?? "Unknown")</p>
                    }
                </div>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card">
                <div class="card-header">Owner Information</div>
                <div class="card-body">
                    <p><strong>Name:</strong> @patient.Owner.FirstName @patient.Owner.LastName</p>
                    <p><strong>Phone:</strong> @patient.Owner.Phone</p>
                    <p><strong>Email:</strong> @patient.Owner.Email</p>
                </div>
            </div>
        </div>
    </div>

    <div class="row mb-4">
        <div class="col-md-8">
            <div class="card">
                <div class="card-header">Medical History</div>
                <div class="card-body">
                    @if (patient.TreatmentNotes.Any())
                    {
                        @foreach (var note in patient.TreatmentNotes)
                        {
                            <div class="border-bottom pb-2 mb-2">
                                <small class="text-muted">@note.CreatedAt.ToString("g") — Dr. @note.Veterinarian</small>
                                <p class="mb-0">@note.Description</p>
                            </div>
                        }
                    }
                    else
                    {
                        <p class="text-muted">No treatment notes yet.</p>
                    }
                </div>
            </div>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-header">Upcoming Appointments</div>
                <div class="card-body">
                    @if (patient.Appointments.Any())
                    {
                        @foreach (var appt in patient.Appointments)
                        {
                            <div class="border-bottom pb-2 mb-2">
                                <strong>@appt.StartTime.ToString("g")</strong>
                                <p class="mb-0 small">@appt.Reason</p>
                            </div>
                        }
                    }
                    else
                    {
                        <p class="text-muted">No upcoming appointments.</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="card">
        <div class="card-header">Add Treatment Note</div>
        <div class="card-body">
            <EditForm Model="newNote" OnValidSubmit="AddNote" FormName="addNoteForm">
                <div class="mb-2">
                    <label class="form-label">Veterinarian</label>
                    <InputText class="form-control" @bind-Value="newNote.Veterinarian" />
                </div>
