</div>

@if (showNewForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5>Book New Appointment</h5>
            <EditForm Model="newAppointment" OnValidSubmit="BookAppointment" FormName="newAppointmentForm">
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-select" @bind-Value="newAppointment.PatientId">
                            <option value="0">-- Select Patient --</option>
                            @foreach (var p in allPatients)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.LastName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Time Slot</label>
                        <InputSelect class="form-select" @bind-Value="selectedSlot">
                            <option value="">-- Select Slot --</option>
                            @foreach (var slot in availableSlots)
                            {
                                <option value="@slot.ToString("o")">@slot.ToString("HH:mm")</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="newAppointment.Reason" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Book</button>
            </EditForm>
        </div>
    </div>
}

<div class="table-responsive">
    <table class="table table-bordered">
        <thead class="table-light">
            <tr>
                <th style="width:100px">Time</th>
                <th>Status</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var slot in allSlots)
            {
                var appointment = appointments.FirstOrDefault(a => a.StartTime == slot);
                <tr>
                    <td><strong>@slot.ToString("HH:mm")</strong></td>
                    @if (appointment != null)
                    {
                        <td class="table-info">
                            <div class="d-flex justify-content-between align-items-center">
                                <span>
                                    <strong>@appointment.Patient.Name</strong> — @appointment.Reason
                                </span>
                                <span>
                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(appointment.Id)">Cancel</button>
                                </span>
                            </div>
                        </td>
                    }
                    else
                    {
                        <td class="table-success text-muted">Available</td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private DateTime selectedDate = DateTime.Today;
    private List<Appointment> appointments = [];
    private List<DateTime> availableSlots = [];
    private List<DateTime> allSlots = [];
    private List<Patient> allPatients = [];
    private Appointment newAppointment = new();
    private string? selectedSlot;
    private bool showNewForm;

    protected override async Task OnInitializedAsync()
    {
        allPatients = await ClinicService.GetAllPatients();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        appointments = await ClinicService.GetAppointmentsForDate(selectedDate);
        availableSlots = await ClinicService.GetAvailableSlots(selectedDate);
        allSlots = [];
        var start = selectedDate.Date.AddHours(8);
        var end = selectedDate.Date.AddHours(18);
        for (var time = start; time < end; time = time.AddMinutes(30))
            allSlots.Add(time);
    }

    private async Task BookAppointment()
    {
        if (newAppointment.PatientId == 0 || string.IsNullOrEmpty(selectedSlot)) return;
        newAppointment.StartTime = DateTime.Parse(selectedSlot);
        newAppointment.Status = AppointmentStatus.Scheduled;
        await ClinicService.CreateAppointment(newAppointment);
        newAppointment = new();
        selectedSlot = null;
        showNewForm = false;
        await LoadAppointments();
    }

    private async Task Cancel(int id)
    {
        await ClinicService.CancelAppointment(id);
        await LoadAppointments();
    }
}

