@code {
    private List<Invoice> invoices = [];
    private List<Patient> allPatients = [];
    private string? statusFilter;
    private bool showForm;
    private Invoice newInvoice = new();
    private List<InvoiceItem> lineItems = [new()];

    protected override async Task OnInitializedAsync()
    {
        allPatients = await ClinicService.GetAllPatients();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        InvoiceStatus? filter = statusFilter switch
        {
            "Pending" => InvoiceStatus.Pending,
            "Paid" => InvoiceStatus.Paid,
            "Cancelled" => InvoiceStatus.Cancelled,
            _ => null
        };
        invoices = await ClinicService.GetAllInvoices(filter);
    }

    private async Task CreateInvoice()
    {
        if (newInvoice.PatientId == 0) return;
        newInvoice.Items = lineItems.Where(i => !string.IsNullOrWhiteSpace(i.Description)).ToList();
        await ClinicService.CreateInvoice(newInvoice);
        newInvoice = new();
        lineItems = [new()];
        showForm = false;
        await LoadInvoices();
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-light"
    };
}

