    {
        newItem.InvoiceId = Id;
        await ClinicService.AddInvoiceItem(newItem);
        newItem = new();
        await LoadInvoice();
    }

    private async Task RemoveItem(int itemId)
    {
        await ClinicService.RemoveInvoiceItem(itemId);
        await LoadInvoice();
    }

    private async Task RecordPayment()
    {
        newPayment.InvoiceId = Id;
        newPayment.PaidAt = DateTime.UtcNow;
        await ClinicService.RecordPayment(newPayment);
        newPayment = new() { Method = "Cash" };
        await LoadInvoice();
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
