@page "/appointments"
@attribute [Authorize]

@inject ClinicService ClinicService

<PageTitle>Appointments - VetClinic</PageTitle>

<h1 class="mb-4">Appointments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">Select Date</label>
