@code {
    private DateTime selectedDate = DateTime.Today;
    private List<Appointment> appointments = [];
    private List<DateTime> availableSlots = [];
    private List<DateTime> allSlots = [];
    private List<Patient> allPatients = [];
    private Appointment newAppointment = new();
    private string? selectedSlot;
    private bool showNewForm;

    protected override async Task OnInitializedAsync()
    {
        allPatients = await ClinicService.GetAllPatients();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        appointments = await ClinicService.GetAppointmentsForDate(selectedDate);
        availableSlots = await ClinicService.GetAvailableSlots(selectedDate);
        allSlots = [];
        var start = selectedDate.Date.AddHours(8);
        var end = selectedDate.Date.AddHours(18);
        for (var time = start; time < end; time = time.AddMinutes(30))
            allSlots.Add(time);
    }

    private async Task BookAppointment()
    {
        if (newAppointment.PatientId == 0 || string.IsNullOrEmpty(selectedSlot)) return;
        newAppointment.StartTime = DateTime.Parse(selectedSlot);
        newAppointment.Status = AppointmentStatus.Scheduled;
        await ClinicService.CreateAppointment(newAppointment);
        newAppointment = new();
        selectedSlot = null;
        showNewForm = false;
        await LoadAppointments();
    }

    private async Task Cancel(int id)
    {
        await ClinicService.CancelAppointment(id);
        await LoadAppointments();
    }
}

